import { useState } from "react";

import {
  registerUser
} from "../../api/authApi";

function Register() {

  const [formData,
    setFormData] =
    useState({

      name: "",
      email: "",
      password: "",

      role: "faculty",

      school: "",

      department: ""
    });

  const handleChange =
    (e) => {

      setFormData({

        ...formData,

        [e.target.name]:
          e.target.value
      });
    };

  const handleSubmit =
    async (e) => {

      e.preventDefault();

      try {

        await registerUser(
          formData
        );

        alert(
          "Registration Successful"
        );

      } catch (error) {

        alert(
          error.response?.data?.message ||
          "Registration Failed"
        );

      }
    };

  return (
    <div
      style={{
        width: "500px",
        margin: "50px auto"
      }}
    >
      <h2>
        Register
      </h2>

      <form
        onSubmit={
          handleSubmit
        }
      >

        <input
          name="name"
          placeholder="Name"
          onChange={
            handleChange
          }
        />

        <br />
        <br />

        <input
          name="email"
          placeholder="Email"
          onChange={
            handleChange
          }
        />

        <br />
        <br />

        <input
          name="password"
          type="password"
          placeholder="Password"
          onChange={
            handleChange
          }
        />

        <br />
        <br />

        <select
          name="role"
          onChange={
            handleChange
          }
        >
          <option value="faculty">
            Faculty
          </option>

          <option value="hod">
            HOD
          </option>

          <option value="dean">
            Dean
          </option>
        </select>

        <br />
        <br />

        <input
          name="school"
          placeholder="School"
          onChange={
            handleChange
          }
        />

        <br />
        <br />

        <input
          name="department"
          placeholder="Department"
          onChange={
            handleChange
          }
        />

        <br />
        <br />

        <button
          type="submit"
        >
          Register
        </button>

      </form>
    </div>
  );
}

export default Register;
